        "rule": "Exceeded limit returns HTTP 429 with a Retry-After header in seconds",
        "testable_assertion": "The 429 response includes a Retry-After header whose value is the number of seconds until enough old requests expire to allow a new one"
      },
      {
        "rule": "The window is truly rolling, not fixed-interval",
        "testable_assertion": "50 requests at T=0 and 50 requests at T=59s must block a request at T=60s (the first 50 haven't expired yet). A fixed window would incorrectly allow it."
      },
      {
        "rule": "Rate limiter must fail open when Redis is unavailable",
        "testable_assertion": "If Redis is unreachable, requests are allowed through and redis_unavailable_total counter is incremented"
      }
