    "architecture_guidance": [
      {
        "decision": "Use Redis sorted sets for a true sliding window (NOT fixed-window counters)",
        "implementation_note": "MJ's original key pattern rate_limit:{api_key}:{window_start_unix} with TTL uses fixed windows, which allows a burst of 2x the limit at window boundaries. Instead: use a single sorted set per API key (key: rate_limit:{api_key}), add each request as a member with score = unix timestamp in ms, ZREMRANGEBYSCORE to prune entries older than 60s, ZCARD to count, all in a single Redis pipeline. Set a 60s TTL on the key as a safety net."
      },
      {
        "decision": "Middleware runs before all authenticated routes",
        "implementation_note": "Extract API key from the authenticated request context. Reject with 429 before any business logic executes."
      },
      {
        "decision": "Retry-After header must be computed dynamically",
        "implementation_note": "With sorted sets: Retry-After = ceiling((oldest_request_in_window_timestamp + 60s) - now). This is the time until the earliest request in the window expires, freeing a slot. Do NOT use a fixed value."
      },
      {
        "decision": "Fail-open on Redis failure",
        "implementation_note": "Wrap all Redis calls in try/catch. On any Redis error, log it, increment redis_unavailable_total counter, and allow the request through. This must have an explicit test."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "101st request in a 60-second window is rejected",
        "given": "An API key has made 100 requests in the last 60 seconds",
        "when": "A 101st request arrives",
        "then": "HTTP 429 is returned with a Retry-After header indicating seconds until a slot frees up"
      },
      {
        "criterion": "Window rolls correctly and resets",
        "given": "An API key made 100 requests starting at T=0",
        "when": "61 seconds have elapsed since the first request",
        "then": "The next request succeeds (the oldest entries have expired out of the window)"
      },
      {
        "criterion": "No boundary burst exploit",
        "given": "An API key sends 99 requests at T=59s of one conceptual window",
        "when": "It sends 99 more requests at T=61s (2 seconds later)",
        "then": "Requests are correctly limited because the sliding window still contains the first 99"
      },
      {
        "criterion": "Fail-open when Redis is down",
        "given": "Redis is unreachable",
        "when": "Any request arrives",
        "then": "The request is allowed through and redis_unavailable_total metric is incremented"
      },
      {
        "criterion": "Observability metrics are emitted",
        "given": "Rate limiting is active",
        "when": "A request is rate-limited OR Redis is unavailable",
        "then": "rate_limit_exceeded_total or redis_unavailable_total counters are incremented respectively"
