      },
      {
        "domain_term": "Retry-After",
        "technical_term": "TTL of oldest sorted set member relative to window edge",
        "definition": "Number of whole seconds until the oldest request in the current window falls outside the 60s range, freeing capacity for a new request."
      }
    ],
